def isSolvable(words, result):
    chars = list({c for w in words + [result] for c in w})
    if len(chars) > 10: return False
    no_leading = set()
    for w in words + [result]:
        if len(w) > 1: no_leading.add(w[0])
    n = len(chars)
    used = [False] * 10
    assign = {}
    def check(col, idx, carry):
        if col == max(len(result), max(len(w) for w in words)):
            return carry == 0
        if idx == len(words) + 1:
            s = carry
            for w in words:
                if col < len(w): s += assign[w[-(col+1)]]
            if col < len(result):
                r = assign[result[-(col+1)]]
                return s % 10 == r and check(col + 1, 0, s // 10)
            else:
                return s == 0
        c = chars[idx] if idx < len(chars) else None
        if c is None: return check(col, len(chars) + 1, carry)
        if c in assign: return check(col, idx + 1, carry)
        for d in range(10):
            if not used[d] and not (d == 0 and c in no_leading):
                used[d] = True; assign[c] = d
                if check(col, idx + 1, carry): return True
                used[d] = False; del assign[c]
        return False
    def bt(i, carry_start):
        if i == n:
            total = carry_start
            for w in words:
                num = sum(assign[c] * 10**(len(w)-1-j) for j,c in enumerate(w))
                total += num
            r = sum(assign[c] * 10**(len(result)-1-j) for j,c in enumerate(result))
            return total == r
        c = chars[i]
        for d in range(10):
            if not used[d] and not (d == 0 and c in no_leading):
                used[d] = True; assign[c] = d
                if bt(i + 1, 0): return True
                used[d] = False; del assign[c]
        return False
    return bt(0, 0)

